#include <bits/stdc++.h>
using namespace std;

const int N=110,INF=1e9;

int n,m,k,p[N],f[N][1<<10],dis[N][N];

int main(){
    memset(dis,0x3f,sizeof(dis));
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=m;i++){
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        if(u==v) continue;
        dis[u][v]=dis[v][u]=min(dis[u][v],w);
    }
    for(int i=1;i<=n;i++) dis[i][i]=0;
    for(int k=1;k<=n;k++)
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++)
                if(dis[i][k]+dis[k][j]<dis[i][j])
                    dis[i][j]=dis[i][k]+dis[k][j];
    for(int i=1,x;i<=k;i++){
        scanf("%d",&x);
        p[x]=i;
    }
    memset(f,0x3f,sizeof(f));
    for(int i=1;i<=n;i++)
        if(p[i]) f[i][1<<p[i]-1]=0;
        else f[i][0]=0;
    for(int i=1;i<1<<k;i++){
        for(int j=1;j<=n;j++)
            for(int w=(i-1)&i;w;w=(w-1)&i)
                f[j][i]=min(f[j][i],f[j][i-w]+f[j][w]); 
        for(int j=1;j<=n;j++)
            for(int u=1;u<=n;u++)
                f[j][i]=min(f[j][i],f[u][i]+dis[j][u]);
    }
    int ans=INF;
    for(int i=1;i<=n;i++)
        ans=min(ans,f[i][(1<<k)-1]);
    printf("%d",ans);
    return 0;
}
